      "each_cycle_aminoacyl_trna_enters_a_sit": "प्रत्येक चक्र — aminoacyl-tRNA, A site मध्ये प्रवेश → peptide bond तयार (23S rRNA, एक ribozyme ने catalyze) → ribosome एक codon सरकते → tRNA, A→P→E जाते।",
      "termination_2": "Termination",
      "stop_codon_uaa_uag_uga_recognized_by_r": "Stop codon (UAA/UAG/UGA) release factor ने ओळखले जाते। Peptide मुक्त होते, ribosome वेगळे होते।",
      "folding_modification": "घडी + बदल",
      "chaperones_hsp70_groel_help_proteins_f": "Chaperone (Hsp70, GroEL) protein ला योग्य घडी घालण्यास मदत करतात। Post-translational modification — phosphorylation, glycosylation, cleavage, disulfide bond।",
      "codon_changes_but_amino_acid_is_the_sa": "Codon बदलते, पण amino acid समान राहते (genetic code redundancy)। कोणताही परिणाम नाही।",
      "codon_changes_different_amino_acid_eff": "Codon बदलते → amino acid वेगळे। परिणाम काहीच नाही (conservative substitution) पासून गंभीर (sickle cell — Glu→Val) पर्यंत।",
      "codon_changes_stop_codon_truncated_pro": "Codon बदलते → STOP codon। Protein कापले जाते, बहुधा non-functional।",
      "adds_nucleotide_s_if_not_a_multiple_of": "nucleotide जोडते। 3 चा गुणक नसल्यास reading frame सरकते → खालचे सर्व codon बदलतात। बहुधा गंभीर।",
      "removes_nucleotide_s_same_frameshift_c": "nucleotide काढते। insertion सारखाच frameshift परिणाम।",
      "extra_copies_of_a_gene_or_region_can_l": "जीन किंवा प्रदेशाच्या अतिरिक्त प्रती। dosage effect आणू शकतात (Down syndrome = अतिरिक्त chromosome 21)।",
      "segment_of_chromosome_flipped_may_disr": "Chromosome चा भाग उलटला। breakpoint वर जीन विस्कळीत करू शकतो।",
      "segment_moves_to_a_different_chromosom": "भाग वेगळ्या chromosome वर सरकतो। प्रसिद्ध — Philadelphia chromosome (CML; BCR-ABL fusion)।",
      "repeating_unit_e_g_cag_expands_across_": "पुनरावृत्त एकक (उदा. CAG) पिढ्यांमध्ये विस्तारते। Huntington (HTT मध्ये CAG), fragile X (FMR1 मध्ये CGG), myotonic dystrophy।",
      "human_autosomes": "मानवी autosome",
      "pairs_1_22_numbered_roughly_by_size_wi": "जोडी 1-22 (आकारानुसार साधारण क्रमांकित, अपवादांसह — chr. 21, chr. 22 पेक्षा लहान)।",
      "sex_chromosomes": "लिंग chromosome",
      "xx_female_or_xy_male_y_is_much_smaller": "XX (स्त्री) किंवा XY (पुरुष)। Y खूप लहान, कमी जीन (~70) वाहून नेते, X (~800) च्या तुलनेत।",
      "total_human_chromosomes": "एकूण मानवी chromosome",
      "23_pairs_diploid_in_somatic_cells_game": "23 जोड्या (somatic cell मध्ये diploid)। Gamete haploid असतात (23 chromosome, कोणतीही जोडी नाही)।",
      "total_human_genes": "एकूण मानवी जीन",
      "surprisingly_few_many_genes_produce_mu": "आश्चर्यकारकरीत्या कमी — अनेक जीन alternative splicing ने अनेक protein तयार करतात। genome चा बहुतांश भाग regulatory किंवा non-coding आहे।",
      "total_base_pairs_haploid": "एकूण base pair (haploid)",
      "if_stretched_out_1_8_m_of_dna_per_cell": "ताणल्यास प्रत्येक cell मागे ~1.8 m DNA। histone + supercoiling ने ~10 µm केंद्रकात सामावले जाते।",
      "mitochondrial_dna": "Mitochondrial DNA",
      "maternally_inherited_codes_for_37_gene": "मातृवारसाहक्काने मिळते। 37 जीन (13 protein, 22 tRNA, 2 rRNA) code करते। प्रत्येक mitochondrion मागे अनेक प्रती।",
      "pcr_polymerase_chain_reaction": "PCR (Polymerase Chain Reaction)",
      "amplifies_a_specific_dna_segment_by_2_": "विशिष्ट DNA भागाचे 2ⁿ (n चक्र) ने वर्धन करते। उष्णता-स्थिर Taq polymerase वापरते। आधुनिक आण्विक जीवशास्त्राचा पाया।",
      "sanger_sequencing": "Sanger sequencing",
      "reads_dna_sequence_using_chain_termina": "chain-terminating dideoxynucleotide वापरून DNA sequence वाचते। Read length ~800-1000 bp। आता बहुधा next-generation sequencing ने बदलले।",
      "next_gen_sequencing_ngs": "Next-generation sequencing (NGS)",
      "massively_parallel_sequences_millions_": "Massively parallel — एकाच वेळी लाखो fragment sequence करते। Illumina वर्चस्व राखते। Read length ~100-300 bp, प्रत्येक run मागे अब्जावधी।",
      "programmable_gene_editing_guide_rna_ta": "Programmable gene editing। Guide RNA, nuclease Cas9 ला विशिष्ट DNA कडे निर्देशित करते। Cut जीन knockout किंवा HDR-mediated insertion करते। Nobel 2020।",
      "crispr_base_editing": "CRISPR base editing",
      "edits_a_single_base_without_double_str": "double-strand break शिवाय एक base संपादित करते। Cas9 पेक्षा कमी off-target effect।",
      "restriction_enzymes": "Restriction enzyme",
      "bacterial_proteins_that_cut_dna_at_spe": "जीवाणू protein जे विशिष्ट 4-8 bp sequence वर DNA कापतात। recombinant DNA technology शक्य केले। Nobel 1978।",
