      "kill_infected_or_cancerous_cells_via_p": "संक्रमित किंवा कर्करोगयुक्त cell ला perforin + granzyme ने मारतात।",
      "y_shaped_proteins_5_classes_igg_most_a": "Y-आकाराचे protein। 5 class — IgG (सर्वाधिक), IgA (mucosa), IgM (प्रारंभिक), IgE (ऍलर्जी + parasite), IgD (B-cell surface)।",
      "cell_surface_molecules_that_present_an": "cell surface molecule जे T cell ला antigen सादर करतात। MHC I (सर्व cell, viral peptide)। MHC II (immune cell, extracellular peptide)।",
      "plasma_proteins_that_punch_holes_in_pa": "plasma protein जे pathogen मध्ये छिद्र पाडतात + phagocyte भरती करतात।",
      "signaling_molecules_of_immune_system_i": "immune system चे signaling molecule। Interferon (antiviral), interleukin (समन्वय), TNF (दाह)।",
      "long_lived_b_t_cells_from_prior_exposu": "पूर्व संपर्कातून दीर्घायुषी B + T cell। vaccine + आजीवन रोगप्रतिकारशक्तीचा आधार।",
      "train_adaptive_immunity_without_diseas": "रोगाशिवाय adaptive immunity प्रशिक्षित करतात। mRNA (COVID), protein subunit, live attenuated, inactivated।",
      "immune_system_attacks_self_type_1_diab": "Immune system स्वतःवर हल्ला करते। Type 1 diabetes, RA, MS, lupus, Hashimoto।",
      "ige_mediated_hypersensitivity_mast_cel": "IgE-mediated hypersensitivity। Mast cell, histamine सोडतात।",
      "dendrites_receive_soma_cell_body_axon_": "Dendrite (प्राप्त), soma (cell body), axon (पाठवते), terminal (neurotransmitter सोडते)।",
      "all_or_none_electrical_signal_sodium_i": "All-or-none electrical signal। Sodium आत → depolarize → potassium बाहेर → repolarize। ~1 ms। Speed — ~1 m/s (unmyelinated) पासून ~100 m/s (myelinated)।",
      "fatty_insulation_made_by_glia_oligoden": "glia (CNS मध्ये oligodendrocyte, PNS मध्ये Schwann cell) ने बनवलेले चरबीयुक्त निरोधन। conduction जलद करते। MS मध्ये नष्ट होते।",
      "junction_between_neurons_electrical_or": "neuron दरम्यान junction। Electrical किंवा chemical (बहुधा)। Gap ~0.02 µm।",
      "chemical_messengers_across_synapse_exc": "synapse ओलांडून chemical messenger। Excitatory (glutamate), inhibitory (GABA), modulatory (serotonin, dopamine)।",
      "reward_motivation_motor_control_low_in": "Reward, motivation, motor control। Parkinson मध्ये कमी; schizophrenia मध्ये dysregulated।",
      "mood_sleep_appetite_ssris_target_reupt": "Mood, झोप, भूक। SSRI, reuptake target करतात।",
      "neuromuscular_junction_memory_attentio": "Neuromuscular junction। Memory + attention। Alzheimer मध्ये कमी।",
      "astrocytes_support_bbb_oligodendrocyte": "Astrocyte (support, BBB), oligodendrocyte (CNS मध्ये myelin), microglia (immune), ependymal cell (cerebrospinal fluid)।",
      "cerebrum_cortex_thinking_perception_ce": "Cerebrum (cortex — विचार, perception), cerebellum (motor coordination), brainstem (autonomic), limbic system (भावना + memory)।",
      "brain_reorganizes_itself_strongest_in_": "मेंदू स्वतःची पुनर्रचना करतो — बालपणात सर्वात प्रबळ, पण आयुष्यभर सुरू। learning चा आधार।",
      "tight_junctions_between_brain_capillar": "brain capillary cell दरम्यान tight junction, बहुतांश molecule बाहेर ठेवतात। CNS मध्ये drug delivery साठी मोठे आव्हान।",
      "20_of_body_s_energy_at_rest_despite_be": "विश्रांतीत शरीराच्या ऊर्जेच्या ~20% (वस्तुमानाच्या ~2% असूनही)। बहुतांश ion gradient राखणाऱ्या Na+/K+ pump साठी।",
      "first_mass_produced_human_protein_made": "पहिले मोठ्या प्रमाणात उत्पादित मानवी protein। E. coli मध्ये बनवले (1982)। डुक्कर + गाय insulin बदलले।",
      "single_target_therapies_humira_autoimm": "Single-target therapy। Humira (autoimmune), Herceptin (HER2+ breast cancer), Keytruda (immunotherapy)।",
      "covid_19_vaccines_pfizer_moderna_self_": "COVID-19 vaccine (Pfizer, Moderna)। Self-amplifying version + non-COVID उपयोग विकासाधीन।",
      "replace_defective_genes_luxturna_inher": "दोषपूर्ण जीन बदलतात। Luxturna (वारसाहक्क अंधत्व, FDA 2017)। Zolgensma (SMA, 2019)।",
      "engineered_immune_cells_yescarta_kymri": "अभियांत्रिकी immune cell। Yescarta + Kymriah, blood cancer साठी। ~$400,000 प्रति dose।",
      "bone_marrow_transplants_standard_for_d": "Bone marrow transplant वर्षानुवर्षे प्रमाण। newer iPSC + ESC approach संशोधनाधीन।",
      "print_tissue_with_living_cells_scaffol": "living cell + scaffold ने tissue print करा। त्वचा, cartilage, मूत्रपिंड। संपूर्ण अवयव अजून दूर।",
      "engineer_biological_systems_bacteria_t": "जैविक यंत्रणा अभियांत्रिकी करा। औषध बनवणारे जीवाणू, opioid बनवणारे yeast, algal biofuel।",
      "bt_corn_insect_resistance_roundup_read": "Bt corn (कीटक प्रतिकार), Roundup Ready (herbicide), Golden Rice (vitamin A)।",
      "str_profiling_mtdna_degraded_samples_y": "STR profiling, mtDNA (क्षीण sample), Y chromosome (पितृ रेषा)। database तुलना।",
